205	
206	        Args.notNull(context, "HTTP context");
207	
208	        if (authChallenge == null) {
209	            if (!challenged) {
210	                // Final response with no Authentication-Info: nothing to do
211	                return;
212	            }
213	            throw new MalformedChallengeException("Null SCRAM challenge");
214	        }
