216	        final Map<String, String> params = toParamMap(authChallenge.getParams());
217	
218	        if (challenged) {
219	            // --- 401 path (WWW-Authenticate) ---
220	            final String scheme = authChallenge.getSchemeName();
221	            if (scheme == null || !StandardAuthScheme.SCRAM_SHA_256.equalsIgnoreCase(scheme)) {
222	                throw new MalformedChallengeException("Unexpected scheme: " + scheme);
223	            }
224	
225	            final String data = params.get("data");
226	            if (data == null) {
227	                // initial announce (no data)
228	                this.realm = params.get("realm");
229	                this.state = State.ANNOUNCED;
230	                this.complete = false;
231	                zeroAndClearExpectedV();
232	                return;
233	            }
234	
235	            // server-first (data present)
236	            final String decoded = b64ToString(data);
237	            this.serverFirstRaw = decoded;
238	            final Map<String, String> attrs = parseAttrs(decoded);
239	
240	            final String r = attrs.get("r");
241	            final String s = attrs.get("s");
242	            final String i = attrs.get("i");
243	            if (r == null || r.isEmpty() || s == null || s.isEmpty() || i == null || i.isEmpty()) {
244	                this.state = State.FAILED;
245	                throw new MalformedChallengeException("SCRAM server-first missing r/s/i");
246	            }
247	            if (this.clientNonce == null || !r.startsWith(this.clientNonce)) {
248	                this.state = State.FAILED;
249	                throw new AuthenticationException("SCRAM server nonce does not start with client nonce");
250	            }
251	
252	            this.sid = params.get("sid");
253	            try {
254	                this.salt = B64D.decode(s);
255	                if (this.salt.length == 0) {
256	                    throw new IllegalArgumentException("empty salt");
257	                }
258	            } catch (final IllegalArgumentException e) {
259	                this.state = State.FAILED;
260	                throw new MalformedChallengeException("Invalid base64 salt", e);
261	            }
262	            try {
263	                this.iterations = Integer.parseInt(i);
264	                if (this.iterations <= 0) {
265	                    throw new NumberFormatException("i<=0");
266	                }
267	            } catch (final NumberFormatException e) {
268	                this.state = State.FAILED;
269	                throw new MalformedChallengeException("Invalid iteration count", e);
270	            }
271	
272	            if (this.minIterationsRequired > 0 && this.iterations < this.minIterationsRequired) {
273	                this.state = State.FAILED;
274	                throw new AuthenticationException(
275	                        "SCRAM iteration count below required minimum: " + this.iterations + " < " + this.minIterationsRequired);
276	            }
277	            if (this.warnMinIterations > 0 && this.iterations < this.warnMinIterations && LOG.isWarnEnabled()) {
278	                LOG.warn("SCRAM iteration count ({}) lower than recommended ({})", this.iterations, warnMinIterations);
279	            }
