301	            }
302	            throw new AuthenticationException("SCRAM server error: " + err);
303	        }
304	        final String vB64 = attrs.get("v");
305	        if (vB64 == null) {
306	            return;
307	        }
308	
309	        // compare 'v' in constant time; treat bad base64 for v as a signature mismatch (tests expect "signature")
310	        final byte[] expected = this.expectedV;
311	        this.expectedV = null; // clear reference early
312	
313	        byte[] vBytes = null;
314	        boolean match;
315	        try {
316	            vBytes = B64D.decode(vB64);
317	            match = expected != null && MessageDigest.isEqual(expected, vBytes);
318	        } catch (final IllegalArgumentException e) {
