442	        this.clientNonce = genNonce();
443	        final String escUser = escapeUser(this.username);
444	        this.clientFirstBare = "n=" + escUser + ",r=" + this.clientNonce;
445	
446	        // RFC 7804: data = base64(GS2 header + client-first-bare)
447	        final String data = stringToB64(GS2_HEADER + this.clientFirstBare);
