461	    private String buildClientFinalAndExpectV() throws AuthenticationException {
462	        byte[] salted = null, clientKey = null, storedKey = null, clientSignature = null,
463	                clientProof = null, serverKey = null, serverSignature = null;
464	
465	        try {
466	            // HTTP SCRAM: no CB -> c=biws
467	            final String clientFinalNoProof = "c=" + C_BIND_B64 + ",r=" + this.serverNonce;
468	            final String authMessage = this.clientFirstBare + "," + this.serverFirstRaw + "," + clientFinalNoProof;
469	
470	            salted = hiPBKDF2(this.password, this.salt, this.iterations, 32);
471	            clientKey = hmac(salted, "Client Key");
472	            storedKey = sha256(clientKey);
473	            clientSignature = hmac(storedKey, authMessage);
474	            clientProof = xor(clientKey, clientSignature);
475	            final String pB64 = B64.encodeToString(clientProof);
476	
477	            serverKey = hmac(salted, "Server Key");
478	            serverSignature = hmac(serverKey, authMessage);
479	
480	            // Stash expected v (raw) for constant-time check on 2xx
481	            zeroAndClearExpectedV();
482	            this.expectedV = serverSignature.clone();
483	
484	            final String clientFinal = clientFinalNoProof + ",p=" + pB64;
485	            final String data = stringToB64(clientFinal);
486	
487	            final StringBuilder sb = new StringBuilder(64);
488	            sb.append(StandardAuthScheme.SCRAM_SHA_256).append(' ');
489	            if (this.sid != null) {
490	                sb.append("sid=").append(quoteParam(this.sid)).append(", ");
491	            }
