 54	/**
 55	 * Default implementation of {@link AuthenticationStrategy}
 56	 *
 57	 * @since 5.0
 58	 */
 59	@Contract(threading = ThreadingBehavior.STATELESS)
 60	public class DefaultAuthenticationStrategy implements AuthenticationStrategy {
 61	
 62	    private static final Logger LOG = LoggerFactory.getLogger(DefaultAuthenticationStrategy.class);
 63	
 64	    /**
 65	     * Default instance of {@link DefaultAuthenticationStrategy}.
 66	     */
 67	    public static final DefaultAuthenticationStrategy INSTANCE = new DefaultAuthenticationStrategy();
 68	
 69	    private static final List<String> DEFAULT_SCHEME_PRIORITY =
 70	            Collections.unmodifiableList(Arrays.asList(
 71	                    StandardAuthScheme.BEARER,
 72	                    StandardAuthScheme.SCRAM_SHA_256,
 73	                    StandardAuthScheme.DIGEST,
 74	                    StandardAuthScheme.BASIC));
 75	
 76	    protected List<String> getSchemePriority() {
 77	        return DEFAULT_SCHEME_PRIORITY;
 78	    }
 79	
 80	    @Override
 81	    public List<AuthScheme> select(
 82	            final ChallengeType challengeType,
 83	            final Map<String, AuthChallenge> challenges,
 84	            final HttpContext context) {
 85	        Args.notNull(challengeType, "ChallengeType");
 86	        Args.notNull(challenges, "Map of auth challenges");
 87	        Args.notNull(context, "HTTP context");
 88	        final HttpClientContext clientContext = HttpClientContext.cast(context);
 89	        final String exchangeId = clientContext.getExchangeId();
 90	
 91	        final List<AuthScheme> options = new ArrayList<>();
 92	        final Lookup<AuthSchemeFactory> registry = clientContext.getAuthSchemeRegistry();
 93	        if (registry == null) {
 94	            if (LOG.isDebugEnabled()) {
 95	                LOG.debug("{} Auth scheme registry not set in the context", exchangeId);
 96	            }
 97	            return options;
 98	        }
 99	        final RequestConfig config = clientContext.getRequestConfigOrDefault();
100	        Collection<String> authPrefs = challengeType == ChallengeType.TARGET ?
101	                config.getTargetPreferredAuthSchemes() : config.getProxyPreferredAuthSchemes();
102	        if (authPrefs == null) {
103	            authPrefs = getSchemePriority();
104	        }
105	        if (LOG.isDebugEnabled()) {
106	            LOG.debug("{} Authentication schemes in the order of preference: {}", exchangeId, authPrefs);
107	        }
108	
109	        for (final String schemeName: authPrefs) {
110	            final AuthChallenge challenge = challenges.get(schemeName.toLowerCase(Locale.ROOT));
111	            if (challenge != null) {
112	                final AuthSchemeFactory authSchemeFactory = registry.lookup(schemeName);
113	                if (authSchemeFactory == null) {
114	                    if (LOG.isWarnEnabled()) {
115	                        LOG.warn("{} Authentication scheme {} not supported", exchangeId, schemeName);
116	                        // Try again
117	                    }
118	                    continue;
119	                }
120	                final AuthScheme authScheme = authSchemeFactory.create(context);
121	                options.add(authScheme);
122	            } else {
123	                if (LOG.isDebugEnabled()) {
124	                    LOG.debug("{} Challenge for {} authentication scheme not available", exchangeId, schemeName);
125	                }
126	            }
127	        }
128	        return options;
129	    }
130	
131	}

