 71	public class AuthenticationHandler {
 72	
 73	    private static final Logger LOG = LoggerFactory.getLogger(AuthenticationHandler.class);
 74	
 75	    private final AuthChallengeParser parser;
 76	
 77	    public AuthenticationHandler() {
 78	        this.parser = new AuthChallengeParser();
 79	    }
 80	
 81	    /**
 82	     * Determines whether the given response represents an authentication challenge, and updates
 83	     * the {@link AuthExchange} state.
 84	     *
 85	     * @param host the hostname of the opposite endpoint.
 86	     * @param challengeType the challenge type (target or proxy).
 87	     * @param response the response message head.
 88	     * @param authExchange the current authentication exchange state. Gets updated.
 89	     * @param context the current execution context.
 90	     * @return {@code true} if the response message represents an authentication challenge,
 91	     *   {@code false} otherwise.
 92	     */
 93	    public boolean isChallenged(
 94	            final HttpHost host,
 95	            final ChallengeType challengeType,
 96	            final HttpResponse response,
 97	            final AuthExchange authExchange,
 98	            final HttpContext context) {
 99	        final HttpClientContext clientContext = HttpClientContext.cast(context);
100	        if (checkChallenged(challengeType, response, clientContext)) {
101	            return true;
102	        }
103	        switch (authExchange.getState()) {
104	        case CHALLENGED:
105	        case HANDSHAKE:
106	            if (LOG.isDebugEnabled()) {
107	                // The mutual auth may still fail
108	                LOG.debug("{} Server has accepted authentication", clientContext.getExchangeId());
109	            }
110	            authExchange.setState(AuthExchange.State.SUCCESS);
111	            break;
112	        case SUCCESS:
113	            break;
114	        default:
115	            authExchange.setState(AuthExchange.State.UNCHALLENGED);
116	        }
117	        return false;
118	    }
119	
120	    /**
121	     * Determines whether the given response represents an authentication challenge
122	     * of challangeType, without changing the {@link AuthExchange} state.
123	     *
124	     * @param challengeType the challenge type (target or proxy).
125	     * @param response the response message head.
126	     * @param clientContext the current execution context.
127	     * @return {@code true} if the response message represents an authentication challenge,
128	     *   {@code false} otherwise.
129	     */
130	    private boolean checkChallenged(
131	            final ChallengeType challengeType,
132	            final HttpResponse response,
133	            final HttpClientContext clientContext) {
134	        final int challengeCode;
135	        switch (challengeType) {
136	            case TARGET:
137	                challengeCode = HttpStatus.SC_UNAUTHORIZED;
138	                break;
139	            case PROXY:
140	                challengeCode = HttpStatus.SC_PROXY_AUTHENTICATION_REQUIRED;
141	                break;
142	            default:
143	                throw new IllegalStateException("Unexpected challenge type: " + challengeType);
144	        }
145	
146	        if (response.getCode() == challengeCode) {
147	            if (LOG.isDebugEnabled()) {
148	                LOG.debug("{} Authentication required", clientContext.getExchangeId());
149	            }
150	            return true;
151	        }
152	        return false;
153	    }
154	
155	    /**
156	     * Determines if the scheme requires an auth challenge for responses that do not
157	     * have a challenge HTTP code. (i.e whether it needs a mutual authentication token)
158	     */
159	    public boolean isChallengeExpected(final AuthExchange authExchange) {
160	        final AuthScheme authScheme = authExchange.getAuthScheme();
161	        return authScheme != null && authScheme.isChallengeExpected();
162	    }
163	
164	    public Map<String, AuthChallenge> extractChallengeMap(
165	            final ChallengeType challengeType,
166	            final HttpResponse response,
167	            final HttpClientContext context) {
168	        final Map<String, AuthChallenge> challengeMap = new HashMap<>();
169	        MessageSupport.parseHeaders(
170	                response,
171	                challengeType == ChallengeType.PROXY ? HttpHeaders.PROXY_AUTHENTICATE : HttpHeaders.WWW_AUTHENTICATE,
172	                (buffer, cursor) -> {
173	                    try {
174	                        final List<AuthChallenge> authChallenges = parser.parse(challengeType, buffer, cursor);
175	                        for (final AuthChallenge authChallenge : authChallenges) {
176	                            final String schemeName = authChallenge.getSchemeName().toLowerCase(Locale.ROOT);
177	                            if (!challengeMap.containsKey(schemeName)) {
178	                                challengeMap.put(schemeName, authChallenge);
179	                            }
180	                        }
181	                    } catch (final ParseException ex) {
182	                        if (LOG.isWarnEnabled()) {
183	                            final HttpClientContext clientContext = HttpClientContext.cast(context);
184	                            final String exchangeId = clientContext.getExchangeId();
185	                            LOG.warn("{} Malformed challenge", exchangeId);
186	                        }
187	                    }
188	
189	                });
190	        return challengeMap;
191	    }
192	
193	    /**
194	     * Handles the response from the opposite endpoint and updates the {@link AuthExchange}
195	     * state based on the challenge presented in the response message using the given
196	     * {@link AuthenticationStrategy}.
197	     *
198	     * @param host the hostname of the opposite endpoint.
199	     * @param challengeType the challenge type (target or proxy).
200	     * @param response the response message head.
201	     * @param authStrategy the authentication strategy.
202	     * @param authExchange the current authentication exchange state.
203	     * @param context the current execution context.
204	     * @return {@code true} if the request needs-to be re-sent,
205	     *   {@code false} if the authentication is complete (successful or not).
206	     *
207	     * @throws AuthenticationException if the AuthScheme throws one. In most cases this indicates a
208	     * client side problem, as final server error responses are simply returned.
209	     * @throws MalformedChallengeException if the AuthScheme throws one. In most cases this indicates a
210	     * client side problem, as final server error responses are simply returned.
211	     */
212	    public boolean handleResponse(
213	            final HttpHost host,
214	            final ChallengeType challengeType,
215	            final HttpResponse response,
216	            final AuthenticationStrategy authStrategy,
217	            final AuthExchange authExchange,
218	            final HttpContext context) throws AuthenticationException, MalformedChallengeException {
219	
220	    final HttpClientContext clientContext = HttpClientContext.cast(context);
221	        final String exchangeId = clientContext.getExchangeId();
222	        final boolean challenged = checkChallenged(challengeType, response, clientContext);
223	        final boolean isChallengeExpected = isChallengeExpected(authExchange);
224	
225	        if (LOG.isDebugEnabled()) {
226	            LOG.debug("{} {} requested authentication", exchangeId, host.toHostString());
227	        }
228	
229	        final Map<String, AuthChallenge> challengeMap = extractChallengeMap(challengeType, response, clientContext);
230	
231	        if (challengeMap.isEmpty()) {
232	            if (LOG.isDebugEnabled()) {
233	                LOG.debug("{} Response contains no valid authentication challenges", exchangeId);
234	            }
235	            if (!isChallengeExpected) {
236	                authExchange.reset();
237	                return false;
238	            }
239	        }
240	
241	        switch (authExchange.getState()) {
242	            case FAILURE:
243	                return false;
244	            case SUCCESS:
245	                if (!isChallengeExpected) {
246	                    authExchange.reset();
247	                    break;
248	                }
249	                // otherwise fall through
250	            case CHALLENGED:
251	                // fall through
252	            case HANDSHAKE:
253	                Asserts.notNull(authExchange.getAuthScheme(), "AuthScheme");
254	                // fall through
255	            case UNCHALLENGED:
256	                final AuthScheme authScheme = authExchange.getAuthScheme();
257	                // AuthScheme is only set if we have already sent an auth response, either
258	                // because we have received a challenge for it, or preemptively.
259	                if (authScheme != null) {
260	                    final String schemeName = authScheme.getName();
261	                    final AuthChallenge challenge = challengeMap.get(schemeName.toLowerCase(Locale.ROOT));
262	                    if (challenge != null || isChallengeExpected) {
263	                        if (LOG.isDebugEnabled()) {
264	                            LOG.debug("{} Processing authentication challenge {}", exchangeId, challenge);
265	                        }
266	                        try {
267	                            authScheme.processChallenge(host, challenged, challenge, clientContext);
268	                        } catch (final AuthenticationException | MalformedChallengeException ex) {
269	                            if (LOG.isWarnEnabled()) {
270	                                LOG.warn("Exception processing challenge {}", exchangeId, ex);
271	                            }
272	                            authExchange.reset();
273	                            authExchange.setState(AuthExchange.State.FAILURE);
274	                            if (isChallengeExpected) {
275	                                throw ex;
276	                            }
277	                        }
278	                        if (authScheme.isChallengeComplete()) {
279	                            if (LOG.isDebugEnabled()) {
280	                                LOG.debug("{} Authentication failed", exchangeId);
281	                            }
282	                            authExchange.reset();
283	                            authExchange.setState(AuthExchange.State.FAILURE);
284	                            return false;
285	                        }
286	                        if (!challenged) {
287	                            // There are no more challanges sent after the 200 message,
288	                            // and if we get here, then the mutual auth phase has succeeded.
289	                            authExchange.setState(AuthExchange.State.SUCCESS);
290	                            return false;
291	                        } else {
292	                            authExchange.setState(AuthExchange.State.HANDSHAKE);
293	                        }
294	                        return true;
295	                    }
296	                    authExchange.reset();
297	                    // Retry authentication with a different scheme
298	                }
299	        }
300	
301	        // We reach this if we fell through above because the authScheme has not yet been set, or if
302	        // we receive a 401/407 response for an unexpected scheme. Normally this processes the first
303	        // 401/407 response
304	        final List<AuthScheme> preferredSchemes = authStrategy.select(challengeType, challengeMap, clientContext);
305	        final CredentialsProvider credsProvider = clientContext.getCredentialsProvider();
306	        if (credsProvider == null) {
307	            if (LOG.isDebugEnabled()) {
308	                LOG.debug("{} Credentials provider not set in the context", exchangeId);
309	            }
310	            return false;
311	        }
312	
313	        final Queue<AuthScheme> authOptions = new LinkedList<>();
314	        if (LOG.isDebugEnabled()) {
315	            LOG.debug("{} Selecting authentication options", exchangeId);
316	        }
317	        for (final AuthScheme authScheme: preferredSchemes) {
318	            // We only respond to the first successfully processed challenge. However, the
319	            // original AuthScheme API does not really process the challenge at this point,
320	            // so we need to process/store each challenge here anyway.
321	            try {
322	                final String schemeName = authScheme.getName();
323	                final AuthChallenge challenge = challengeMap.get(schemeName.toLowerCase(Locale.ROOT));
324	                authScheme.processChallenge(host, challenged, challenge, clientContext);
325	                if (authScheme.isResponseReady(host, credsProvider, clientContext)) {
326	                    authOptions.add(authScheme);
327	                }
328	            } catch (final AuthenticationException | MalformedChallengeException ex) {
329	                if (LOG.isWarnEnabled()) {
330	                    LOG.warn("Exception while processing Challange", ex);
331	                }
332	            }
333	        }
334	        if (!authOptions.isEmpty()) {
335	            if (LOG.isDebugEnabled()) {
336	                LOG.debug("{} Selected authentication options: {}", exchangeId, authOptions);
337	            }
338	            authExchange.reset();
339	            authExchange.setState(AuthExchange.State.CHALLENGED);
340	            authExchange.setOptions(authOptions);
341	            return true;
342	        }
343	        return false;
344	    }
