 67	
 68	    static String b64(final byte[] b) {
 69	        return Base64.getEncoder().withoutPadding().encodeToString(b);
 70	    }
 71	
 72	    static byte[] b64d(final String s) {
 73	        return Base64.getDecoder().decode(s);
 74	    }
 75	
 76	    static String b64s(final String s) {
 77	        return b64(s.getBytes(StandardCharsets.UTF_8));
 78	    }
 79	
 80	    static String deb64s(final String s) {
 81	        return new String(b64d(s), StandardCharsets.UTF_8);
 82	    }
 83	
 84	    static Map<String, String> parseCsvAttrs(final String s) {
 85	        final Map<String, String> m = new LinkedHashMap<>();
 86	        int i = 0;
 87	        while (i < s.length()) {
 88	            final int eq = s.indexOf('=', i);
 89	            if (eq < 0) break;
 90	            final String k = s.substring(i, eq);
 91	            i = eq + 1;
 92	            final StringBuilder v = new StringBuilder();
 93	            while (i < s.length()) {
 94	                final char c = s.charAt(i);
 95	                if (c == ',') {
 96	                    i++;
 97	                    break;
 98	                }
 99	                v.append(c);
100	                i++;
101	            }
102	            m.put(k, v.toString());
103	        }
104	        return m;
105	    }
106	
107	    static Map<String, String> splitHeader(final String header) {
108	        // "SCRAM-SHA-256 realm="...", data="..."" -> name/value map (lowercase keys)
109	        final int sp = header.indexOf(' ');
110	        final String params = header.substring(sp + 1);
111	        final Map<String, String> map = new HashMap<>();
112	        for (String part : params.split(",")) {
113	            part = part.trim();
114	            final int eq = part.indexOf('=');
115	            if (eq > 0) {
116	                final String k = part.substring(0, eq).toLowerCase(Locale.ROOT);
117	                String v = part.substring(eq + 1);
118	                if (v.length() >= 2 && v.startsWith("\"") && v.endsWith("\"")) {
119	                    v = v.substring(1, v.length() - 1);
120	                }
121	                map.put(k, v);
122	            }
123	        }
124	        return map;
125	    }
126	
127	    static byte[] pbkdf2(final char[] password, final byte[] salt, final int iter, final int dkLen)
128	            throws GeneralSecurityException {
129	        final PBEKeySpec spec = new PBEKeySpec(password, salt, iter, dkLen * 8);
130	        return SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256").generateSecret(spec).getEncoded();
131	    }
132	
133	    static byte[] hmac(final byte[] key, final String msg) throws GeneralSecurityException {
134	        final Mac mac = Mac.getInstance("HmacSHA256");
135	        mac.init(new SecretKeySpec(key, "HmacSHA256"));
136	        return mac.doFinal(msg.getBytes(StandardCharsets.UTF_8));
137	    }
