141	    void strictScram_fullRoundtrip_completes() throws Exception {
142	        final ScramScheme scheme = new ScramScheme();
143	        final BasicCredentialsProvider creds = new BasicCredentialsProvider();
144	        creds.setCredentials(new AuthScope(HOST, REALM, scheme.getName()),
145	                new UsernamePasswordCredentials(USER, PASS.toCharArray()));
146	        final HttpClientContext ctx = HttpClientContext.create();
147	
148	        // 401 announce (no data)
149	        scheme.processChallenge(HOST, true,
150	                new AuthChallenge(ChallengeType.TARGET, scheme.getName(),
151	                        new BasicNameValuePair("realm", REALM)),
152	                ctx);
153	        assertTrue(scheme.isResponseReady(HOST, creds, ctx));
154	
155	        // Authorization (client-first)
156	        final String authz1 = scheme.generateAuthResponse(HOST, null, ctx);
157	        final Map<String, String> h1 = splitHeader(authz1);
158	        assertEquals(REALM, h1.get("realm"));
159	        final String clientFirst = deb64s(h1.get("data"));
160	        assertTrue(clientFirst.startsWith("n,,"), "GS2 header missing");
161	        final String clientFirstBare = clientFirst.substring("n,,".length());
162	        final Map<String, String> cf1 = parseCsvAttrs(clientFirstBare);
163	        final String clientNonce = cf1.get("r");
164	        assertNotNull(clientNonce);
165	
166	        // 401 server-first
167	        final String saltB64 = b64("salt-256".getBytes(StandardCharsets.UTF_8));
168	        final int iters = 4096;
