171	                new AuthChallenge(ChallengeType.TARGET, scheme.getName(),
172	                        new BasicNameValuePair("sid", "sid-1"),
173	                        new BasicNameValuePair("data", b64(serverFirst.getBytes(StandardCharsets.UTF_8)))),
