181	        assertEquals("biws", cf2.get("c")); // Base64("n,,")
182	
183	        final String clientFinalNoProof = "c=" + cf2.get("c") + ",r=" + cf2.get("r");
184	        final String authMessage = clientFirstBare + "," + serverFirst + "," + clientFinalNoProof;
185	        final byte[] salted = pbkdf2(PASS.toCharArray(), b64d(saltB64), iters, 32);
186	        final byte[] serverKey = hmac(salted, "Server Key");
187	        final String vB64 = b64(hmac(serverKey, authMessage));
188	
189	        scheme.processChallenge(HOST, false,
190	                new AuthChallenge(ChallengeType.TARGET, scheme.getName(),
191	                        new BasicNameValuePair("data", b64(("v=" + vB64).getBytes(StandardCharsets.UTF_8)))),
192	                ctx);
