 44	/**
 45	 * {@code NextNonceInterceptor} is an HTTP response interceptor that extracts the {@code nextnonce}
 46	 * parameter from the {@code Authentication-Info} header of an HTTP response. This parameter is used
 47	 * in HTTP Digest Access Authentication to provide an additional nonce value that the client is expected
 48	 * to use in subsequent authentication requests. By retrieving and storing this {@code nextnonce} value,
 49	 * the interceptor facilitates one-time nonce implementations and prevents replay attacks by ensuring that
 50	 * each request/response interaction includes a fresh nonce.
 51	 * <p>
 52	 * If present, the extracted {@code nextnonce} value is stored in the {@link HttpContext} under the attribute
 53	 * {@code auth-nextnonce}, allowing it to be accessed in subsequent requests. If the header does not contain
 54	 * the {@code nextnonce} parameter, no context attribute is set.
 55	 * </p>
 56	 *
 57	 * <p>This implementation adheres to the HTTP/1.1 specification, particularly focusing on the {@code Digest}
 58	 * scheme as defined in HTTP Digest Authentication, and parses header tokens using the {@link Tokenizer}
 59	 * utility class for robust token parsing.</p>
 60	 *
 61	 * <p>In the context of HTTP Digest Access Authentication, the {@code nextnonce} parameter is
 62	 * a critical part of the security mechanism, designed to mitigate replay attacks and enhance mutual
 63	 * authentication security. It provides the server with the ability to set and enforce single-use or
 64	 * session-bound nonces, prompting the client to use the provided {@code nextnonce} in its next request.
 65	 * This setup helps secure communication by forcing new cryptographic material in each transaction.
 66	 * </p>
 67	 *
 68	 * <p>This interceptor is stateless and thread-safe, making it suitable for use across multiple
 69	 * threads and HTTP requests. It should be registered with the HTTP client to enable support
 70	 * for advanced authentication mechanisms that require tracking of nonce values.</p>
 71	 *
 72	 * @since 5.5
 73	 */
 74	
 75	@Contract(threading = ThreadingBehavior.STATELESS)
 76	public class NextNonceInterceptor implements HttpResponseInterceptor {
 77	
 78	    public static final HttpResponseInterceptor INSTANCE = new NextNonceInterceptor();
 79	
 80	    private final Tokenizer tokenParser = Tokenizer.INSTANCE;
 81	
 82	
 83	    private static final String AUTHENTICATION_INFO_HEADER = "Authentication-Info";
 84	
 85	    private static final Tokenizer.Delimiter TOKEN_DELIMS = Tokenizer.delimiters('=', ',');
 86	    private static final Tokenizer.Delimiter VALUE_DELIMS = Tokenizer.delimiters(',');
 87	
 88	    /**
 89	     * Processes the HTTP response and extracts the {@code nextnonce} parameter from the
 90	     * {@code Authentication-Info} header if available, storing it in the provided {@code context}.
 91	     *
 92	     * @param response the HTTP response containing the {@code Authentication-Info} header
 93	     * @param entity   the response entity, ignored by this interceptor
 94	     * @param context  the HTTP context in which to store the {@code nextnonce} parameter
 95	     * @throws NullPointerException if either {@code response} or {@code context} is null
 96	     */
 97	    @Override
 98	    public void process(final HttpResponse response, final EntityDetails entity, final HttpContext context) {
 99	        Args.notNull(response, "HTTP response");
100	        Args.notNull(context, "HTTP context");
101	
102	        final Header header = response.getFirstHeader(AUTHENTICATION_INFO_HEADER);
103	        if (header != null) {
104	            final String nextNonce;
105	            if (header instanceof FormattedHeader) {
106	                final CharSequence buf = ((FormattedHeader) header).getBuffer();
107	                final ParserCursor cursor = new ParserCursor(((FormattedHeader) header).getValuePos(), buf.length());
108	                nextNonce = parseNextNonce(buf, cursor);
109	            } else {
110	                final CharSequence headerValue = header.getValue();
111	                final ParserCursor cursor = new ParserCursor(0, headerValue.length());
112	                nextNonce = parseNextNonce(headerValue, cursor);
113	            }
114	            if (!TextUtils.isBlank(nextNonce)) {
115	                HttpClientContext.castOrCreate(context).setNextNonce(nextNonce);
116	            }
117	        }
118	    }
119	
120	    /**
121	     * Parses the {@code Authentication-Info} header content represented by a {@link CharArrayBuffer}
122	     * to extract the {@code nextnonce} parameter.
123	     *
124	     * @param buffer the {@link CharArrayBuffer} containing the value of the {@code Authentication-Info} header
125	     * @param cursor the {@link ParserCursor} used to navigate through the buffer content
