 41	import org.apache.hc.core5.util.Tokenizer;
 42	
 43	/**
 44	 * Authentication challenge parser.
 45	 *
 46	 * @since 5.0
 47	 */
 48	public class AuthChallengeParser {
 49	
 50	    /**
 51	     * Default instance of {@link AuthChallengeParser}.
 52	     */
 53	    public static final AuthChallengeParser INSTANCE = new AuthChallengeParser();
 54	
 55	    private final Tokenizer tokenParser = Tokenizer.INSTANCE;
 56	
 57	    private final static char BLANK = ' ';
 58	    private final static char COMMA_CHAR = ',';
 59	    private final static char EQUAL_CHAR = '=';
 60	
 61	    private static final Tokenizer.Delimiter TERMINATORS = Tokenizer.delimiters(BLANK, EQUAL_CHAR, COMMA_CHAR);
 62	    private static final Tokenizer.Delimiter DELIMITER = Tokenizer.delimiters(COMMA_CHAR);
 63	    private static final Tokenizer.Delimiter SPACE = Tokenizer.delimiters(BLANK);
 64	
 65	    static class ChallengeInt {
 66	
 67	        final String schemeName;
 68	        final List<NameValuePair> params;
 69	
 70	        ChallengeInt(final String schemeName) {
 71	            this.schemeName = schemeName;
 72	            this.params = new ArrayList<>();
 73	        }
 74	
 75	        @Override
 76	        public String toString() {
 77	            return "ChallengeInternal{" +
 78	                    "schemeName='" + schemeName + '\'' +
 79	                    ", params=" + params +
 80	                    '}';
 81	        }
 82	
 83	    }
 84	
 85	    /**
 86	     * Parses the given sequence of characters into a list of {@link AuthChallenge} elements.
 87	     *
 88	     * @param challengeType the type of challenge (target or proxy).
 89	     * @param buffer the sequence of characters to be parsed.
 90	     * @param cursor the parser cursor.
 91	     * @return a list of auth challenge elements.
 92	     */
 93	    public List<AuthChallenge> parse(
 94	            final ChallengeType challengeType, final CharSequence buffer, final ParserCursor cursor) throws ParseException {
 95	        tokenParser.skipWhiteSpace(buffer, cursor);
 96	        if (cursor.atEnd()) {
 97	            throw new ParseException("Malformed auth challenge");
 98	        }
 99	        final List<ChallengeInt> internalChallenges = new ArrayList<>();
100	        final String schemeName = tokenParser.parseToken(buffer, cursor, SPACE);
101	        if (TextUtils.isBlank(schemeName)) {
102	            throw new ParseException("Malformed auth challenge");
103	        }
104	        ChallengeInt current = new ChallengeInt(schemeName);
105	        while (current != null) {
106	            internalChallenges.add(current);
107	            current = parseChallenge(buffer, cursor, current);
108	        }
109	        final List<AuthChallenge> challenges = new ArrayList<>(internalChallenges.size());
110	        for (final ChallengeInt internal : internalChallenges) {
111	            challenges.add(parseInt(challengeType, internal));
112	        }
113	        return challenges;
114	    }
115	
116	    /**
117	     * Parses the given sequence of characters into a single {@link AuthChallenge}.
118	     *
119	     * @param challengeType the type of challenge (target or proxy).
120	     * @param schemeName the scheme name
121	     * @param buffer the sequence of characters to be parsed.
122	     * @param cursor the parser cursor.
123	     * @return auth challenge.
124	     *
125	     * @since 5.7
126	     */
127	    public AuthChallenge parse(
128	            final ChallengeType challengeType,
129	            final String schemeName,
130	            final CharSequence buffer,
131	            final ParserCursor cursor) {
132	        final List<NameValuePair> params = new ArrayList<>();
133	        while (!cursor.atEnd()) {
134	            final NameValuePair param = BasicHeaderValueParser.INSTANCE.parseNameValuePair(buffer, cursor);
135	            params.add(param);
136	            if (!cursor.atEnd()) {
137	                final char ch = buffer.charAt(cursor.getPos());
138	                if (ch == ',') {
139	                    cursor.updatePos(cursor.getPos() + 1);
140	                }
141	            }
142	        }
143	        return new AuthChallenge(challengeType, schemeName, null, params);
144	    }
145	
146	    AuthChallenge parseInt(final ChallengeType challengeType, final ChallengeInt internal) {
147	        final List<NameValuePair> params = internal.params;
148	        String token68 = null;
149	        if (params.size() == 1) {
150	            final NameValuePair param = params.get(0);
151	            if (param.getValue() == null) {
152	                token68 = param.getName();
153	                params.clear();
154	            }
155	        }
156	        return new AuthChallenge(challengeType, internal.schemeName, token68, !params.isEmpty() ? params : null);
157	    }
158	
159	    ChallengeInt parseChallenge(
160	            final CharSequence buffer,
161	            final ParserCursor cursor,
162	            final ChallengeInt currentChallenge) throws ParseException {
163	        for (;;) {
164	            tokenParser.skipWhiteSpace(buffer, cursor);
165	            if (cursor.atEnd()) {
166	                return null;
167	            }
168	            final String token = parseToken(buffer, cursor);
169	            if (TextUtils.isBlank(token)) {
170	                throw new ParseException("Malformed auth challenge");
171	            }
172	            tokenParser.skipWhiteSpace(buffer, cursor);
173	
174	            // it gets really messy here
175	            if (cursor.atEnd()) {
176	                // at the end of the header
177	                currentChallenge.params.add(new BasicNameValuePair(token, null));
178	            } else {
179	                char ch = buffer.charAt(cursor.getPos());
180	                if (ch == EQUAL_CHAR) {
181	                    cursor.updatePos(cursor.getPos() + 1);
182	                    final String value = tokenParser.parseValue(buffer, cursor, DELIMITER);
183	                    tokenParser.skipWhiteSpace(buffer, cursor);
184	                    if (!cursor.atEnd()) {
185	                        ch = buffer.charAt(cursor.getPos());
186	                        if (ch == COMMA_CHAR) {
187	                            cursor.updatePos(cursor.getPos() + 1);
188	                        }
189	                    }
190	                    currentChallenge.params.add(new BasicNameValuePair(token, value));
191	                } else if (ch == COMMA_CHAR) {
192	                    cursor.updatePos(cursor.getPos() + 1);
193	                    currentChallenge.params.add(new BasicNameValuePair(token, null));
194	                } else {
195	                    // the token represents new challenge
196	                    if (currentChallenge.params.isEmpty()) {
197	                        throw new ParseException("Malformed auth challenge");
198	                    }
199	                    return new ChallengeInt(token);
200	                }
201	            }
202	        }
203	    }
204	
205	    String parseToken(final CharSequence buf, final ParserCursor cursor) {
206	        final StringBuilder dst = new StringBuilder();
207	        while (!cursor.atEnd()) {
208	            int pos = cursor.getPos();
209	            char current = buf.charAt(pos);
210	            if (TERMINATORS.test(current)) {
211	                // Here it gets really ugly
212	                if (current == EQUAL_CHAR) {
213	                    // it can be a start of a parameter value or token68 padding
214	                    // Look ahead and see if there are more '=' or at end of buffer
215	                    if (pos + 1 < cursor.getUpperBound() && buf.charAt(pos + 1) != EQUAL_CHAR) {
216	                        break;
217	                    }
218	                    do {
219	                        dst.append(current);
220	                        pos++;
221	                        cursor.updatePos(pos);
222	                        if (cursor.atEnd()) {
223	                            break;
224	                        }
225	                        current = buf.charAt(pos);
226	                    } while (current == EQUAL_CHAR);
227	                } else {
228	                    break;
229	                }
230	            } else {
231	                dst.append(current);
232	                cursor.updatePos(pos + 1);
233	            }
234	        }
235	        return dst.toString();
236	    }
237	
238	}

