196	    private AuthChallenge extractChallenge(
197	            final ChallengeType challengeType,
198	            final HttpResponse response,
199	            final AuthScheme authScheme,
200	            final boolean challenged,
201	            final HttpClientContext context) {
202	        if (challenged) {
203	            final Map<String, AuthChallenge> challengeMap = extractChallengeMap(challengeType, response, context);
204	            return challengeMap.get(authScheme.getName().toLowerCase(Locale.ROOT));
205	        }
