214	                    authScheme.getName(),
215	                    header.getValue(),
216	                    new ParserCursor(0, header.getValue().length()));
217	        } catch (final ParseException ex) {
218	            if (LOG.isWarnEnabled()) {
219	                LOG.warn("{} Malformed authentication info", context.getExchangeId());
