261	        final Map<String, AuthChallenge> challengeMap = extractChallengeMap(challengeType, response, clientContext);
262	
263	        if (challengeMap.isEmpty()) {
264	            if (LOG.isDebugEnabled()) {
265	                LOG.debug("{} Response contains no valid authentication challenges", exchangeId);
266	            }
267	            if (!isChallengeExpected) {
268	                authExchange.reset();
269	                return false;
270	            }
271	        }
272	
273	        switch (authExchange.getState()) {
274	            case FAILURE:
275	                return false;
276	            case SUCCESS:
277	                if (!isChallengeExpected) {
278	                    authExchange.reset();
279	                    break;
280	                }
281	                // otherwise fall through
282	            case CHALLENGED:
