297	                        try {
298	                            authScheme.processChallenge(host, challenged, challenge, clientContext);
299	                        } catch (final AuthenticationException | MalformedChallengeException ex) {
300	                            if (LOG.isWarnEnabled()) {
301	                                LOG.warn("Exception processing challenge {}", exchangeId, ex);
302	                            }
